<script>
    'use strict';
    var gameData = { stat_data: {}, delta_data: null };

    const ThemeManager = {
        THEME_KEY: 'xiyao-status-theme', currentTheme: 'day',
        init() { this.themeButtons = document.querySelectorAll('.theme-btn'); this.loadSavedTheme(); this.addEventListeners(); return this; },
        loadSavedTheme() { this.currentTheme = localStorage.getItem(this.THEME_KEY) || 'day'; this.applyTheme(this.currentTheme); },
        applyTheme(theme) { document.body.className = `theme-${theme}`; this.updateActiveButton(theme); localStorage.setItem(this.THEME_KEY, theme); },
        updateActiveButton(theme) { this.themeButtons.forEach(btn => btn.classList.toggle('active', btn.dataset.theme === theme)); },
        addEventListeners() { this.themeButtons.forEach(button => button.addEventListener('click', () => this.handleThemeClick(button))); },
        handleThemeClick(button) { const theme = button.dataset.theme; if (theme !== this.currentTheme) this.applyTheme(theme); }
    };

    function deepGet(obj, path) {
        if (typeof path !== 'string') return undefined;
        return path.split('.').reduce((prev, curr) => (prev ? prev[curr] : undefined), obj);
    }

    function SafeGetValue(value, defaultValue = "N/A") {
        if (value === undefined || value === null) return defaultValue;
        if (Array.isArray(value)) return value.length > 0 ? String(value[0]) : defaultValue;
        return String(value);
    }

    function toggleSection(element) {
        element.classList.toggle('expanded');
        const content = element.nextElementSibling;
        content.classList.toggle('expanded');
    }

    function updateProgressBar(barId, valueSpanId, value, min, max) {
        const progressBar = document.getElementById(barId);
        const valueSpan = document.getElementById(valueSpanId);
        if (!valueSpan) return;

        let displayValue = SafeGetValue(value, String(min));
        let finalValueText = displayValue.split('->').pop().trim();
        valueSpan.innerText = displayValue;

        let numericValue = parseFloat(finalValueText.match(/-?\d+(\.\d+)?/)?.[0] || String(min));

        if (!progressBar || isNaN(numericValue)) return;

        const range = max - min;
        const boundedValue = Math.max(min, Math.min(numericValue, max));
        const percentage = range === 0 ? 0 : ((boundedValue - min) / range) * 100;

        progressBar.style.width = `${percentage}%`;
        progressBar.style.marginLeft = '0'; // Always start from the left

        progressBar.style.backgroundColor = boundedValue >= 0 ? 'var(--progress-bar-positive)' : 'var(--progress-bar-negative)';
    }


    function updateElement(elementId, value) {
        const element = document.getElementById(elementId);
        if (element) {
            element.innerText = SafeGetValue(value);
            element.closest('.property')?.classList.remove('hidden');
        }
    }

    function updateDisplay() {
        const showDeltaOnly = document.getElementById('data-toggle').checked;
        const toggleLabel = document.getElementById('toggle-label-text');
        localStorage.setItem('showDeltaOnly', String(showDeltaOnly));
        toggleLabel.innerText = showDeltaOnly ? '仅显示变更' : '显示全部';
        toggleLabel.classList.toggle('active', showDeltaOnly);

        document.querySelectorAll('.property').forEach(p => p.classList.add('hidden'));

        const paths = {
            '世界.日期': 'world-date', '世界.时间': 'world-time', '世界.当前地点': 'world-location', '世界.家庭可支出余额': 'world-balance',
            '夏汐.好感度': 'xixi-affection', '夏汐.穿着': 'xixi-outfit', '夏汐.身体状态': 'xixi-body-status', '夏汐.动作体位': 'xixi-posture', '夏汐.心理活动': 'xixi-psychology',
            '夏瑶.好感度': 'xiyao-affection', '夏瑶.穿着': 'xiyao-outfit', '夏瑶.身体状态': 'xiyao-body-status', '夏瑶.动作体位': 'xiyao-posture', '夏瑶.心理活动': 'xiyao-psychology'
        };

        const dataSource = showDeltaOnly && gameData.delta_data ? gameData.delta_data : gameData.stat_data;

        for (const path in paths) {
            if (path.includes('好感度')) continue;
            const value = deepGet(dataSource, path);
            if (value !== undefined) {
                 updateElement(paths[path], value);
            }
        }

        const xixiAffectionValue = showDeltaOnly && gameData.delta_data && deepGet(gameData.delta_data, '夏汐.好感度') !== undefined
            ? deepGet(gameData.delta_data, '夏汐.好感度')
            : deepGet(gameData.stat_data, '夏汐.好感度');
        if (xixiAffectionValue !== undefined) {
            updateProgressBar('xixi-affection-bar', 'xixi-affection', xixiAffectionValue, -100, 200);
            document.getElementById('xixi-affection-prop').classList.remove('hidden');
        }

        const xiyaoAffectionValue = showDeltaOnly && gameData.delta_data && deepGet(gameData.delta_data, '夏瑶.好感度') !== undefined
            ? deepGet(gameData.delta_data, '夏瑶.好感度')
            : deepGet(gameData.stat_data, '夏瑶.好感度');
         if (xiyaoAffectionValue !== undefined) {
            updateProgressBar('xiyao-affection-bar', 'xiyao-affection', xiyaoAffectionValue, -100, 200);
            document.getElementById('xiyao-affection-prop').classList.remove('hidden');
        }

        document.querySelectorAll('.section').forEach(section => {
          const visibleProperties = section.querySelectorAll('.property:not(.hidden)');
          section.classList.toggle('hidden', visibleProperties.length === 0);
        });
    }

    async function initDisplayLogic() {
        try {
            document.querySelectorAll('.section-header, .section-content').forEach(el => el.classList.add('expanded'));

            const messages = await getChatMessages(getCurrentMessageId());
            if (!messages || !messages[0] || !messages[0].data) {
                document.getElementById('status-card').innerHTML = "<p style='color:red; padding:10px;'>无法加载状态数据。</p>";
                return;
            }
            gameData.stat_data = messages[0].data.stat_data || {};
            gameData.delta_data = messages[0].data.delta_data || null;

            const toggleElement = document.getElementById('data-toggle');
            if (gameData.delta_data && Object.keys(gameData.delta_data).length > 0) {
                 toggleElement.disabled = false;
                 toggleElement.checked = localStorage.getItem('showDeltaOnly') === 'true';
            } else {
                 toggleElement.disabled = true;
                 toggleElement.checked = false;
            }
            updateDisplay();
        } catch (error) {
            document.getElementById('status-card').innerHTML = `<p style='color:red; padding:10px;'>状态栏加载出错: ${error.message}</p>`;
        }
    }

    document.getElementById('data-toggle').addEventListener('change', updateDisplay);

    document.addEventListener('DOMContentLoaded', function() {
        ThemeManager.init();
        if (typeof getChatMessages === 'function' && typeof getCurrentMessageId === 'function') {
            initDisplayLogic();
        } else {
            gameData = {
                stat_data: {
                  "世界": { "日期": ["2025年5月10日"], "时间": ["15:00"], "当前地点": ["客厅"], "家庭可支出余额": ["¥1,500.00"] },
                  "夏汐": { "好感度": [-50], "穿着": ["白色连衣裙"], "身体状态": ["健康"], "动作体位": ["坐在沙发上"], "心理活动": ["有点无聊"] },
                  "夏瑶": { "好感度": [150], "穿着": ["蓝色运动装"], "身体状态": ["精神饱满"], "动作体位": ["在厨房准备点心"], "心理活动": ["待会儿给他一个惊喜"] }
                },
                delta_data: {
                    "夏汐": { "好感度": ["-50 -> -48 (+2)"] },
                    "夏瑶": { "心理活动": ["待会儿给他一个惊喜 -> 他怎么还不来，点心要凉了。"] }
                }
            };
            initDisplayLogic();
        }
    });

</script>
</body>
</html>
